VALUES
  ('promotion-6f0ba476-moex-00125', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X1年底流通在外普通股共150,000股，每股面額$10。X2年5月宣告於7月1日發放 10%的股票股利。X2年12月甲公司購入庫藏股票30,000股，每股成本$25，至X3年2月以 每股$28出售5,000股庫藏股票。X3年5月 1日宣告將於7月1日發放每股$1.2的現金股 利，則X3年5月1日甲公司記錄其現金股利宣告之分錄，應將保留盈餘：', '["增加$150,000", "減少$168,000", "增加$165,000", "減少$183,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00126', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司採備抵法提列預期信用減損損失（呆帳）。X1年銷貨收入淨額共計$1,500,000，其中現 金銷貨為$780,000，賒銷為$720,000。X1年期初應收帳款餘額為$280,000，期末應收帳款餘額 為$210,000。X1年沖銷應收帳款$9,000。試計算甲公司X1年度現金基礎下之銷貨收入：', '["$780,000", "$850,000", "$1,561,000", "$1,570,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00127', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月份銷貨於乙公司相關資訊如下： 1/3 甲公司賖銷$70,000商品於乙公司，所有權移轉條件為目的地交貨，付款條件為2/10,n/30， 此批商品之成本為$28,000，並支付銷貨運費$2,000。甲公司以毛額法記錄商品賖銷之交易。 1/8 因商品部分瑕疵，乙公司退回售價$8,000之商品，其原始成本為$2,400，估計淨變現價值 為$1,500。 1/13 收到1/3賖銷產生之部分應收帳款$40,000。 1/28 收到1/3賖銷產生之其餘應收帳款。 請問甲公司完成上述1月份銷貨之銷貨毛利率為何？', '["53.43%", "56.70%", "57.26%", "59.17%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00128', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司為鋼珠筆批發商，採永續盤存制，並以移動平均法作為存貨評價方法。在12月份有下 列紀錄或交易： 12/1 存貨3,000支，單價$18。 12/5 進貨2,000支，單價$19，進貨運費$400，因部分顏色與訂購單不吻合，退回200支，另 因部分外表損傷賣方折讓$600。 12/9 賣出2,800支，售價$35，銷貨運費$700。 12/18 進貨2,500支，單價$20，進貨運費$650，因部分外表損傷賣方折讓$480。 12/31 盤點時，發現部分鋼珠筆未完善保存，以致無法銷售，提列備抵存貨跌價$4,700。 請問甲公司於 12 月份關於鋼珠筆之銷貨成本為多少？（單位成本請計算至小數點後第二位 四捨五入）', '["$51,464", "$53,004", "$56,024", "$56,164"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00129', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司以應收帳款餘額百分比法為估計預期信用減損損失，估計預期損失率為8%。X1年及X2 年底應收帳款淨額分別為$552,000及$874,000，X2年沖銷確定無法收回之應收帳款$25,000，X2 年預期信用減損損失為$50,760。請問X2年沖銷後再回收之應收帳款金額為多少？', '["$0", "$2,240", "$5,840", "$25,760"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00130', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司10月31日銀行對帳單餘額較公司帳面現金餘額之90%多$2,000，並發現下列事項： ⑴已存入銀行之在途存款$82,000。 ⑵銀行已完成託收票據收款，票面金額$28,500。 ⑶銀行收取服務費$1,200，直接從存款帳戶扣除。 ⑷未兌支票為$53,000。 ⑸銀行結算出存款利息$164，直接記入公司的存款帳戶。 ⑹銀行誤將幫忙乙公司託收票據之$2,370，記入甲公司的存款帳戶中。 ⑺存款不足退票（notsufficieutfund）為$48,000。 ⑻甲公司將編號2266銀行已兌付支票$8,320以$8,230入帳。 請問甲公司10月31日之銀行對帳單餘額為多少？', '["$441,684", "$443,684", "$486,344", "$490,760"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00131', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '下列那一帳戶在編製結帳分錄結清餘額時，需要借記損益彙總帳？', '["服務收入", "預付工程款", "股利", "水電費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00132', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司與乙顧客簽訂銷貨合約，約定以單價$300銷貨500件。銷貨合約給予顧客退貨權，讓 顧客於45天內無條件退貨，公司須全額退費，每件商品的成本為$180。假設此銷貨合約適用 國際財務報導準則第15號「客戶合約收入」，比較下列二種情境。 情境一：預估有20件商品將被退回。 情境二：預估有50件商品將被退回。 若以情境一為基準，請問關於情境二下列那些銷貨當日的分錄處理敘述正確？', '["借記應收帳款金額較低", "貸記銷貨收入金額較低", "借記銷貨成本金額較低", "貸記存貨金額較低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00133', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '請問下列有關無形資產之敘述何者正確？', '["發生價值減損後，若未來價值回升，非確定耐用年限之無形資產可將減損損失迴轉", "為保護專利權之訴訟支出，若訴訟結果為勝訴時，因結果有助於維持該專利權之未來經濟 效益，可資本化訴訟支出，並在未來期間進行攤銷", "公司開業前推出新產品或新服務之支出，為具有經濟效益的開辦費，可認列為無形資產", "商譽僅於發生減損跡象時，進行減損測試"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00134', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-112-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年10月1日發行三年期、面額$400,000、利率10%，每年3月31日及9月30 日付息之公司債。發行時市場利率為8%，發行價格為$426,934。請問該公司債發行期間利息 費用合計為多少？', '["$88,000", "$93,066", "$120,000", "$146,934"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:29+00:00", "source_pdf_sha1": "f3d59328de4e", "answer_pdf_sha1": "a929678ff5f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
